#include <stdio.h>
#define MOD 1000000007LL
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    long long fact[101]; fact[0]=1;
    for(int i=1;i<=100;++i) fact[i]=fact[i-1]*i%MOD;
    while(T--){
        int N,K; scanf("%d %d",&N,&K);
        long long ans;
        if(N>K) ans=fact[K];
        else{ ans=1; for(int i=0;i<N;++i) ans=ans*(K-i)%MOD; }
        printf("%lld\n",ans);
    }
    return 0;
}

