import sys
MOD = 1000000007
fact = [1]*101
for i in range(1,101):
    fact[i] = fact[i-1]*i % MOD

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); K = int(next(it))
        if N > K:
            ans = fact[K]
        else:
            ans = 1
            for i in range(N):
                ans = ans * (K - i) % MOD
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

